using System;
using System.Linq;
using System.Reflection;
var assertType = typeof(Microsoft.VisualStudio.TestTools.UnitTesting.Assert);
var methods = assertType.GetMethods(BindingFlags.Public | BindingFlags.Static)
    .Where(m => m.Name is "AreEqual" or "AreNotEqual" or "AreSame" or "AreNotSame")
    .OrderBy(m => m.Name);
